function largestSumSequence(nums, k) {
    const minHeap = new MinHeap();

    for (const num of nums) {
        minHeap.push(num);
        if (minHeap.getSize() > k) {
            minHeap.pop();
        }
    }

    const result = new Array(k);
    for (let i = k - 1; i >= 0; i--) {
        result[i] = minHeap.pop();
    }

    return result;
}

class MinHeap {
    constructor() {
        this.heap = [];
    }

    push(num) {
        this.heap.push(num);
        this.bubbleUp(this.heap.length - 1);
    }

    pop() {
        const min = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.bubbleDown(0);
        return min;
    }

    getSize() {
        return this.heap.length;
    }

    bubbleUp(index) {
        while (index > 0 && this.heap[index] < this.heap[Math.floor((index - 1) / 2)]) {
            this.swap(index, Math.floor((index - 1) / 2));
            index = Math.floor((index - 1) / 2);
        }
    }

    bubbleDown(index) {
        while (2 * index + 1 < this.heap.length) {
            let minIndex = 2 * index + 1;
            if (2 * index + 2 < this.heap.length && this.heap[minIndex] > this.heap[2 * index + 2]) {
                minIndex = 2 * index + 2;
            }
            if (this.heap[index] > this.heap[minIndex]) {
                this.swap(index, minIndex);
                index = minIndex;
            } else {
                break;
            }
        }
    }

    swap(i, j) {
        const tmp = this.heap[i];
        this.heap[i] = this.heap[j];
        this.heap[j] = tmp;
    }
}
```

    The algorithm uses a min-heap of size `k` to keep track of the largest `k` elements in the input array. It iterates through the array, pushing each element to the heap. If the heap has more than `k` elements, it pops the smallest element. After processing all elements, the min-heap contains the desired subsequence having the largest sum, and we just need to transform the heap back to an array with the same order of elements.

